154→  // Normalize these so RunOptions fields (noLog, noMcp, etc.) work correctly.
155→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
156→  const cliOpts = options as any;
157→  const normalizedOptions: RunOptions = {
158→    ...options,
159→    ...(cliOpts.log === false && { noLog: true }),
160→    ...(cliOpts.smartTests === false && { noSmartTests: true }),
161→    ...(cliOpts.mcp === false && { noMcp: true }),
162→    ...(cliOpts.retry === false && { noRetry: true }),
163→    ...(cliOpts.rebase === false && { noRebase: true }),
164→    ...(cliOpts.pr === false && { noPr: true }),
165→  };
166→
167→  const mergedOptions: RunOptions = {
168→    // Settings defaults (phases removed - now auto-detected)
169→    sequential: normalizedOptions.sequential ?? settings.run.sequential,
170→    concurrency: normalizedOptions.concurrency ?? settings.run.concurrency,
171→    timeout: normalizedOptions.timeout ?? settings.run.timeout,
172→    logPath: normalizedOptions.logPath ?? settings.run.logPath,
173→    qualityLoop: normalizedOptions.qualityLoop ?? settings.run.qualityLoop,
