183→  // Determine if we should auto-detect phases from labels
184→  const autoDetectPhases = !options.phases && settings.run.autoDetectPhases;
185→  mergedOptions.autoDetectPhases = autoDetectPhases;
186→
187→  // Resolve base branch: CLI flag → settings.run.defaultBase → auto-detect → 'main'
188→  const resolvedBaseBranch =
189→    options.base ??
190→    settings.run.defaultBase ??
191→    detectDefaultBranch(mergedOptions.verbose ?? false);
192→
193→  // Parse issue numbers (or use batch mode)
194→  let issueNumbers: number[];
195→  let batches: number[][] | null = null;
196→
197→  if (mergedOptions.batch && mergedOptions.batch.length > 0) {
198→    batches = parseBatches(mergedOptions.batch);
199→    issueNumbers = batches.flat();
200→    console.log(
