 63→/**
 64→ * Resolve the CLI binary path to avoid nested npx version mismatches (#389).
 65→ *
 66→ * Priority:
 67→ * 1. process.argv[1] — the script currently running (works for npx, global, local node)
 68→ * 2. __dirname-relative resolution — fallback for bundled/compiled entry points
 69→ * 3. "npx" + "sequant" — last resort if nothing else resolves
 70→ *
 71→ * Returns [command, prefixArgs] where the full invocation is:
 72→ *   spawnAsync(command, [...prefixArgs, "run", ...userArgs])
 73→ */
 74→export function resolveCliBinary(): [string, string[]] {
 75→  // Try process.argv — most reliable across npx, global install, and local node
 76→  const nodeExe = process.argv[0];
 77→  const scriptPath = process.argv[1];
 78→
 79→  if (scriptPath && existsSync(scriptPath)) {
 80→    // If the entry point is a .ts file (e.g. running via `npx tsx bin/cli.ts serve`),
 81→    // the child process won't have tsx's loader hooks. Prefer the compiled dist output,
 82→    // or fall through to use tsx explicitly.
 83→    if (!scriptPath.endsWith(".ts")) {
 84→      return [nodeExe, [scriptPath]];
 85→    }
 86→
 87→    // Try compiled dist equivalent: bin/cli.ts → dist/bin/cli.js
 88→    const distPath = resolve(
 89→      dirname(scriptPath),
 90→      "..",
 91→      "dist",
 92→      "bin",
 93→      "cli.js",
 94→    );
 95→    if (existsSync(distPath)) {
 96→      return [process.execPath, [distPath]];
 97→    }
 98→
 99→    // Use tsx to run the .ts file directly
100→    return ["npx", ["tsx", scriptPath]];
101→  }
102→
103→  // Fallback: resolve relative to this file's location (dist/src/mcp/tools/run.js → dist/bin/cli.js)
104→  const cliPath = resolve(dirname(__dirname), "..", "..", "bin", "cli.js");
105→  if (existsSync(cliPath)) {
106→    return [process.execPath, [cliPath]];
107→  }
108→
109→  // Last resort: fall back to npx (original behavior)
110→  return ["npx", ["sequant"]];
111→}
