113→/**
114→ * Resolve the log directory path (project-level or user-level)
115→ */
116→function resolveLogDir(): string {
117→  const projectPath = LOG_PATHS.project;
118→  if (existsSync(projectPath)) {
119→    return projectPath;
120→  }
121→
122→  const userPath = LOG_PATHS.user.replace("~", homedir());
123→  if (existsSync(userPath)) {
124→    return userPath;
125→  }
126→
127→  return projectPath;
128→}
