175→/**
176→ * Build a structured response from a parsed RunLog
177→ */
178→export function buildStructuredResponse(
179→  runLog: RunLog,
180→  rawOutput: string,
181→  overallStatus: "success" | "failure",
182→  exitCode?: number | null,
183→  errorOutput?: string,
184→): RunToolResponse {
185→  const issues: RunToolIssueSummary[] = runLog.issues.map((issue) => {
186→    // Find QA verdict from phase logs
187→    const qaPhase = issue.phases.find((p) => p.phase === "qa");
188→    const verdict = qaPhase?.verdict;
189→
190→    return {
191→      issueNumber: issue.issueNumber,
192→      status: issue.status,
193→      phases: issue.phases.map((p) => ({
194→        phase: p.phase,
195→        status: p.status,
196→        durationSeconds: p.durationSeconds,
197→      })),
198→      ...(verdict ? { verdict } : {}),
199→      durationSeconds: issue.totalDurationSeconds,
200→    };
201→  });
202→
203→  const phasesRan = [
204→    ...new Set(runLog.issues.flatMap((i) => i.phases.map((p) => p.phase))),
205→  ].join(",");
206→
207→  const response: RunToolResponse = {
208→    status: overallStatus,
209→    ...(exitCode != null && exitCode !== 0 ? { exitCode } : {}),
210→    issues,
211→    summary: {
212→      total: runLog.summary.totalIssues,
213→      passed: runLog.summary.passed,
214→      failed: runLog.summary.failed,
215→      durationSeconds: runLog.summary.totalDurationSeconds,
216→    },
217→    phases: phasesRan || runLog.config.phases.join(","),
218→    rawOutput: rawOutput.slice(-MAX_RAW_OUTPUT),
219→    ...(errorOutput ? { error: errorOutput.slice(-1000) } : {}),
220→  };
221→
222→  return enforceResponseSizeLimit(response);
223→}
224→
225→/**
226→ * Enforce response size limit by progressively truncating rawOutput.
227→ * Uses Buffer.byteLength for accurate UTF-8 byte measurement.
228→ */
229→function enforceResponseSizeLimit(response: RunToolResponse): RunToolResponse {
230→  let json = JSON.stringify(response);
231→  let byteLength = Buffer.byteLength(json, "utf-8");
232→
233→  if (byteLength <= MAX_RESPONSE_SIZE) {
234→    return response;
235→  }
236→
237→  // Progressively truncate rawOutput to fit
238→  const rawOutput = response.rawOutput || "";
239→  if (rawOutput.length > 0) {
240→    const excess = byteLength - MAX_RESPONSE_SIZE;
241→    // Over-trim slightly: multi-byte chars mean char count < byte count
242→    const newLength = Math.max(0, rawOutput.length - excess - 200);
243→
244→    response.rawOutput =
245→      newLength > 0 ? rawOutput.slice(-newLength) : undefined;
246→
247→    json = JSON.stringify(response);
248→    byteLength = Buffer.byteLength(json, "utf-8");
249→  }
250→
251→  // If still too large (structured data itself is huge), truncate error field
252→  if (byteLength > MAX_RESPONSE_SIZE && response.error) {
253→    const excess = byteLength - MAX_RESPONSE_SIZE;
254→    const newLength = Math.max(0, response.error.length - excess - 200);
255→    response.error =
256→      newLength > 0 ? response.error.slice(-newLength) : undefined;
257→  }
258→
259→  return response;
260→}
