288→/** Prefix used by the batch executor to emit structured progress lines. */
289→const PROGRESS_LINE_PREFIX = "SEQUANT_PROGRESS:";
290→
291→/** Parsed progress event from a SEQUANT_PROGRESS line. */
292→export interface ProgressEvent {
293→  issue: number;
294→  phase: string;
295→  event: "start" | "complete" | "failed";
296→  durationSeconds?: number;
297→  error?: string;
298→}
299→
300→/**
301→ * Parse a SEQUANT_PROGRESS line emitted by the batch executor.
302→ * Returns the parsed event or null if the line isn't a progress line.
303→ */
304→export function parseProgressLine(line: string): ProgressEvent | null {
305→  if (!line.startsWith(PROGRESS_LINE_PREFIX)) return null;
306→  try {
307→    const json = JSON.parse(line.slice(PROGRESS_LINE_PREFIX.length));
308→    if (
309→      typeof json.issue === "number" &&
310→      typeof json.phase === "string" &&
311→      typeof json.event === "string" &&
312→      (json.event === "start" ||
313→        json.event === "complete" ||
314→        json.event === "failed")
315→    ) {
316→      const result: ProgressEvent = {
317→        issue: json.issue,
318→        phase: json.phase,
319→        event: json.event,
320→      };
321→      if (typeof json.durationSeconds === "number") {
322→        result.durationSeconds = json.durationSeconds;
323→      }
324→      if (typeof json.error === "string") {
325→        result.error = json.error;
326→      }
327→      return result;
328→    }
329→    return null;
330→  } catch {
331→    return null;
332→  }
333→}
334→
335→/**
336→ * Build a human-readable message for a progress notification (AC-3).
337→ * @internal Exported for testing only.
338→ */
339→export function formatProgressMessage(event: ProgressEvent): string {
340→  const prefix = `#${event.issue}`;
341→  switch (event.event) {
342→    case "start":
343→      return `${prefix}: ${event.phase} started`;
344→    case "complete": {
345→      const dur = event.durationSeconds ? ` (${event.durationSeconds}s)` : "";
346→      return `${prefix}: ${event.phase} \u2713${dur}`;
347→    }
348→    case "failed": {
349→      const reason = event.error ? ` \u2014 ${event.error}` : "";
350→      return `${prefix}: ${event.phase} \u2717${reason}`;
351→    }
352→  }
353→}
