355→/**
356→ * Create a line buffer that accumulates stream chunks and yields complete lines.
357→ * Handles the case where a single `data` event spans partial lines.
358→ */
359→export function createLineBuffer(
360→  onLine: (line: string) => void,
361→): (chunk: string) => void {
362→  let buffer = "";
363→  return (chunk: string) => {
364→    buffer += chunk;
365→    const lines = buffer.split("\n");
366→    buffer = lines.pop()!; // keep incomplete tail
367→    for (const line of lines) {
368→      if (line.length > 0) onLine(line);
369→    }
370→  };
371→}
