396→export function registerRunTool(server: McpServer): void {
397→  server.registerTool(
398→    "sequant_run",
399→    {
400→      title: "Sequant Run",
401→      description:
402→        "Execute structured AI workflow phases for GitHub issues. " +
403→        "Runs spec (plan) → exec (implement) → qa (review) in sequence, creating worktrees and PRs. " +
404→        "Long-running: up to 30 minutes per issue. Returns structured JSON with per-issue phase results. " +
405→        "Check sequant_status first to avoid re-running completed issues. " +
406→        "Example: {issues: [123], phases: 'spec,exec'}",
407→      annotations: {
408→        readOnlyHint: false,
409→        destructiveHint: false,
410→        idempotentHint: false,
411→        openWorldHint: true,
412→      },
413→      inputSchema: runToolInputSchema,
414→    },
415→    (async (
416→      {
417→        issues,
418→        phases,
419→        qualityLoop,
420→        agent,
421→      }: {
422→        issues: number[];
423→        phases?: string;
424→        qualityLoop?: boolean;
425→        agent?: string;
426→      },
427→      extra: ToolHandlerExtra,
428→    ) => {
429→      if (!issues || issues.length === 0) {
430→        return {
431→          content: [
432→            {
433→              type: "text" as const,
434→              text: JSON.stringify({
435→                error: "INVALID_INPUT",
436→                message: "At least one issue number is required",
437→              }),
438→            },
439→          ],
440→          isError: true,
441→        };
442→      }
443→
444→      // Resolve CLI binary to avoid nested npx version mismatch (#389)
445→      const [command, prefixArgs] = resolveCliBinary();
446→
447→      // Build command arguments
448→      const args = [...prefixArgs, "run", ...issues.map(String)];
449→      if (phases) {
450→        args.push("--phases", phases);
451→      }
452→      if (qualityLoop) {
453→        args.push("--quality-loop");
454→      }
455→      if (agent) {
456→        args.push("--agent", agent);
457→      }
458→      args.push("--log-json");
459→
460→      const phasesStr = phases || "spec,exec,qa";
461→      const phaseList = phasesStr.split(",");
462→      const totalSteps = issues.length * phaseList.length;
463→      const runStartTime = new Date();
464→
465→      // Extract progress token for MCP progress notifications (AC-1)
466→      const progressToken = extra._meta?.progressToken;
467→
468→      // Track progress: only complete/failed events increment the counter
469→      let completedSteps = 0;
470→
471→      /**
472→       * Emit a progress notification if the client provided a progressToken.
473→       * Only complete/failed events increment the progress counter.
474→       * Failures are caught to avoid aborting the run (AC-6).
475→       */
476→      const emitProgress = (event: ProgressEvent): void => {
477→        if (progressToken === undefined) return;
478→        if (event.event === "complete" || event.event === "failed") {
479→          completedSteps++;
480→        }
481→        try {
482→          // Fire-and-forget: don't await to avoid blocking the output stream
483→          void extra
484→            .sendNotification({
485→              method: "notifications/progress",
486→              params: {
487→                progressToken,
488→                progress: completedSteps,
489→                total: totalSteps,
490→                message: formatProgressMessage(event),
491→              },
492→            })
493→            .catch(() => {
494→              // Swallow notification delivery errors (AC-6)
495→            });
496→        } catch {
497→          // Swallow synchronous errors (AC-6)
498→        }
499→      };
500→
501→      /**
502→       * Handle a complete line of subprocess stderr, checking for progress events.
503→       * The batch executor emits SEQUANT_PROGRESS:{json} lines at phase boundaries.
504→       */
505→      const handleLine = (line: string): void => {
506→        const event = parseProgressLine(line);
507→        if (event) emitProgress(event);
508→      };
509→
510→      // Line-buffer stderr to handle chunk boundaries correctly.
511→      // When a progressToken is present, we also enable spawnAsync's
512→      // internal progress detection for timeout reset (AC-4).
513→      const hasProgressToken = progressToken !== undefined;
514→      const stderrLineBuffer = hasProgressToken
515→        ? createLineBuffer(handleLine)
516→        : undefined;
517→
518→      // Register all issues as active runs for real-time status polling
519→      for (const issue of issues) {
520→        registerRun(issue);
521→      }
522→
523→      try {
524→        const result = await spawnAsync(command, args, {
525→          timeout: PHASE_TIMEOUT,
526→          env: {
527→            ...process.env,
528→            SEQUANT_ORCHESTRATOR: "mcp-server",
529→          },
530→          signal: extra.signal,
531→          onStderr: stderrLineBuffer,
532→          // Enable timeout reset on progress events when client
533→          // provided a progressToken (AC-4). spawnAsync detects
534→          // SEQUANT_PROGRESS lines from stderr internally.
535→          onProgress: hasProgressToken ? () => {} : undefined,
536→        });
537→
538→        const stdout = result.stdout || "";
539→        const stderr = result.stderr || "";
540→        const overallStatus: "success" | "failure" =
541→          result.exitCode === 0 ? "success" : "failure";
542→
543→        // Try to read structured log file for rich per-issue data
544→        const runLog = await readLatestRunLog(runStartTime);
545→
546→        let response: RunToolResponse;
547→        if (runLog) {
548→          response = buildStructuredResponse(
549→            runLog,
550→            stdout,
551→            overallStatus,
552→            result.exitCode,
553→            stderr || undefined,
554→          );
555→        } else {
556→          // Fallback: no log file available
557→          response = buildFallbackResponse(
558→            stdout,
559→            issues,
560→            overallStatus,
561→            phasesStr,
562→            result.exitCode,
563→            stderr || undefined,
564→          );
565→        }
566→
567→        return {
568→          content: [
569→            {
570→              type: "text" as const,
571→              text: JSON.stringify(response),
572→            },
573→          ],
574→          ...(result.exitCode !== 0 ? { isError: true } : {}),
575→        };
576→      } catch (error) {
577→        return {
578→          content: [
579→            {
580→              type: "text" as const,
581→              text: JSON.stringify({
582→                error: "EXECUTION_ERROR",
583→                message: error instanceof Error ? error.message : String(error),
584→              }),
585→            },
586→          ],
587→          isError: true,
588→        };
589→      } finally {
590→        for (const issue of issues) {
591→          unregisterRun(issue);
592→        }
593→      }
594→    }) as Parameters<typeof server.registerTool>[2],
595→  );
596→}
