598→export interface SpawnResult {
599→  exitCode: number | null;
600→  stdout: string;
601→  stderr: string;
602→}
603→
604→/** Per-phase timeout ceiling (30 minutes) */
605→export const PHASE_TIMEOUT = 1_800_000;
606→
607→/** Absolute maximum run duration (2 hours), even with progress resets */
608→export const MAX_TOTAL_TIMEOUT = 7_200_000;
609→
610→export interface SpawnOptions {
611→  timeout: number;
612→  env?: NodeJS.ProcessEnv;
613→  signal?: AbortSignal;
614→  /** Called with each stderr chunk (real-time, before process exits) */
615→  onStderr?: (chunk: string) => void;
616→  /** Called with each stdout chunk (real-time, before process exits) */
617→  onStdout?: (chunk: string) => void;
618→  /**
619→   * Called when a progress event is detected from stderr.
620→   * When set, enables resettable timeout: the per-phase timeout resets on
621→   * each SEQUANT_PROGRESS line, but the absolute ceiling still applies.
622→   */
623→  onProgress?: () => void;
624→  /**
625→   * Override the absolute timeout ceiling (defaults to MAX_TOTAL_TIMEOUT).
626→   * Only applies when onProgress is set. Useful for testing.
627→   * @internal
628→   */
629→  maxTotalTimeout?: number;
630→}
631→
632→/** @internal Exported for testing only */
633→export function spawnAsync(
634→  command: string,
635→  args: string[],
636→  options: SpawnOptions,
637→): Promise<SpawnResult> {
638→  return new Promise((resolve, reject) => {
639→    let stdout = "";
640→    let stderr = "";
641→    let settled = false;
642→
643→    const proc = spawn(command, args, {
644→      stdio: ["pipe", "pipe", "pipe"],
645→      env: options.env,
646→      detached: true,
647→    });
648→
649→    const settle = (
650→      outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
651→    ) => {
652→      if (settled) return;
653→      settled = true;
654→      clearTimeout(timeoutId);
655→      options.signal?.removeEventListener("abort", onAbort);
656→      if (outcome.ok) {
657→        resolve(outcome.result);
658→      } else {
659→        reject(outcome.error);
660→      }
661→    };
662→
663→    // Resettable timeout: resets on progress events (AC-4).
664→    // Uses options.timeout as the per-phase ceiling and MAX_TOTAL_TIMEOUT
665→    // as the absolute ceiling to prevent infinite runs.
666→    const runStart = Date.now();
667→    const maxTotal = options.onProgress
668→      ? (options.maxTotalTimeout ?? MAX_TOTAL_TIMEOUT)
669→      : options.timeout;
670→
671→    const scheduleTimeout = (): ReturnType<typeof setTimeout> => {
672→      const elapsed = Date.now() - runStart;
673→      const remaining = Math.min(options.timeout, maxTotal - elapsed);
674→      if (remaining <= 0) {
675→        // Already exceeded max total — kill immediately
676→        killProcessGroup(proc);
677→        settle({
678→          ok: false,
679→          error: new Error(
680→            `Process exceeded maximum total timeout of ${maxTotal}ms`,
681→          ),
682→        });
683→        return setTimeout(() => {}, 0); // dummy handle
684→      }
685→      return setTimeout(() => {
686→        killProcessGroup(proc);
687→        const msg = options.onProgress
688→          ? `Process timed out: no progress for ${options.timeout}ms (total elapsed: ${Date.now() - runStart}ms)`
689→          : `Process timed out after ${options.timeout}ms`;
690→        settle({ ok: false, error: new Error(msg) });
691→      }, remaining);
692→    };
693→
694→    let timeoutId = scheduleTimeout();
695→
696→    // When progress monitoring is enabled, detect SEQUANT_PROGRESS lines
697→    // from stderr and reset the timeout on each one. This keeps the timeout
698→    // reset logic co-located with the timer inside spawnAsync (AC-4).
699→    const resetTimeout = () => {
700→      if (!settled) {
701→        clearTimeout(timeoutId);
702→        timeoutId = scheduleTimeout();
703→      }
704→    };
705→
706→    const progressLineBuffer = options.onProgress
707→      ? createLineBuffer((line) => {
708→          if (line.startsWith(PROGRESS_LINE_PREFIX)) {
709→            resetTimeout();
710→            options.onProgress!();
711→          }
712→        })
713→      : undefined;
714→
715→    const onAbort = () => {
716→      killProcessGroup(proc);
717→      settle({ ok: false, error: new Error("Cancelled by client") });
718→    };
719→
720→    if (options.signal) {
721→      if (options.signal.aborted) {
722→        killProcessGroup(proc);
723→        clearTimeout(timeoutId);
724→        reject(new Error("Cancelled by client"));
725→        return;
726→      }
727→      options.signal.addEventListener("abort", onAbort, { once: true });
728→    }
729→
730→    proc.stdout.on("data", (data: Buffer) => {
731→      const chunk = data.toString();
732→      stdout += chunk;
733→      options.onStdout?.(chunk);
734→    });
735→
736→    proc.stderr.on("data", (data: Buffer) => {
737→      const chunk = data.toString();
738→      stderr += chunk;
739→      options.onStderr?.(chunk);
740→      progressLineBuffer?.(chunk);
741→    });
742→
743→    proc.on("error", (err: NodeJS.ErrnoException) => {
744→      if (err.code === "ENOENT") {
745→        settle({
746→          ok: false,
747→          error: new Error(
748→            `Command not found: ${command}. Ensure it is installed and in PATH.`,
749→          ),
750→        });
751→      } else {
752→        settle({
753→          ok: false,
754→          error: new Error(`Failed to spawn process: ${err.message}`),
755→        });
756→      }
757→    });
758→
759→    proc.on("close", (code: number | null) => {
760→      settle({ ok: true, result: { exitCode: code, stdout, stderr } });
761→    });
762→  });
763→}
