765→const SIGKILL_GRACE_MS = 5000;
766→
767→function killProcessGroup(proc: ReturnType<typeof spawn>): void {
768→  let exited = false;
769→  proc.on("close", () => {
770→    exited = true;
771→  });
772→
773→  sendSignal(proc, "SIGTERM");
774→
775→  setTimeout(() => {
776→    if (!exited) {
777→      sendSignal(proc, "SIGKILL");
778→    }
779→  }, SIGKILL_GRACE_MS).unref();
780→}
781→
782→function sendSignal(
783→  proc: ReturnType<typeof spawn>,
784→  signal: NodeJS.Signals,
785→): void {
786→  try {
787→    if (proc.pid) {
788→      process.kill(-proc.pid, signal);
789→    }
790→  } catch {
791→    // Process group may already be gone — fall back to direct kill
792→    if (!proc.killed) {
793→      proc.kill(signal);
794→    }
795→  }
796→}
