 310→/**
 311→ * Parse environment variables for CI configuration
 312→ */
 313→export function getEnvConfig(): Partial<RunOptions> {
 314→  const config: Partial<RunOptions> = {};
 315→
 316→  if (process.env.SEQUANT_QUALITY_LOOP === "true") {
 317→    config.qualityLoop = true;
 318→  }
 319→
 320→  if (process.env.SEQUANT_MAX_ITERATIONS) {
 321→    const maxIter = parseInt(process.env.SEQUANT_MAX_ITERATIONS, 10);
 322→    if (!isNaN(maxIter)) {
 323→      config.maxIterations = maxIter;
 324→    }
 325→  }
 326→
 327→  if (process.env.SEQUANT_SMART_TESTS === "false") {
 328→    config.noSmartTests = true;
 329→  }
 330→
 331→  if (process.env.SEQUANT_TESTGEN === "true") {
 332→    config.testgen = true;
 333→  }
 334→
 335→  return config;
 336→}
