 338→export async function executeBatch(
 339→  issueNumbers: number[],
 340→  config: ExecutionConfig,
 341→  logWriter: LogWriter | null,
 342→  stateManager: StateManager | null,
 343→  options: RunOptions,
 344→  issueInfoMap: Map<number, { title: string; labels: string[] }>,
 345→  worktreeMap: Map<number, WorktreeInfo>,
 346→  shutdownManager?: ShutdownManager,
 347→  packageManager?: string,
 348→  baseBranch?: string,
 349→): Promise<IssueResult[]> {
 350→  const results: IssueResult[] = [];
 351→
 352→  for (const issueNumber of issueNumbers) {
 353→    // Check if shutdown was triggered
 354→    if (shutdownManager?.shuttingDown) {
 355→      break;
 356→    }
 357→
 358→    const issueInfo = issueInfoMap.get(issueNumber) ?? {
 359→      title: `Issue #${issueNumber}`,
 360→      labels: [],
 361→    };
 362→    const worktreeInfo = worktreeMap.get(issueNumber);
 363→
 364→    // Start issue logging
 365→    if (logWriter) {
 366→      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
 367→    }
 368→
 369→    const result = await runIssueWithLogging(
 370→      issueNumber,
 371→      config,
 372→      logWriter,
 373→      stateManager,
 374→      issueInfo.title,
 375→      issueInfo.labels,
 376→      options,
 377→      worktreeInfo?.path,
 378→      worktreeInfo?.branch,
 379→      shutdownManager,
 380→      false, // Batch mode doesn't support chain
 381→      packageManager,
 382→      undefined,
 383→      baseBranch,
 384→    );
 385→    results.push(result);
 386→
 387→    // Record PR info in log before completing issue
 388→    if (logWriter && result.prNumber && result.prUrl) {
 389→      logWriter.setPRInfo(result.prNumber, result.prUrl);
 390→    }
 391→
 392→    // Complete issue logging
 393→    if (logWriter) {
 394→      logWriter.completeIssue();
 395→    }
 396→  }
 397→
 398→  return results;
 399→}
 400→
 401→export async function runIssueWithLogging(
 402→  issueNumber: number,
 403→  config: ExecutionConfig,
 404→  logWriter: LogWriter | null,
 405→  stateManager: StateManager | null,
 406→  issueTitle: string,
 407→  labels: string[],
 408→  options: RunOptions,
 409→  worktreePath?: string,
 410→  branch?: string,
 411→  shutdownManager?: ShutdownManager,
 412→  chainMode?: boolean,
 413→  packageManager?: string,
 414→  isLastInChain?: boolean,
 415→  baseBranch?: string,
 416→): Promise<IssueResult> {
 417→  const startTime = Date.now();
 418→  const phaseResults: PhaseResult[] = [];
 419→  let loopTriggered = false;
 420→  let sessionId: string | undefined;
 421→
 422→  // In parallel mode, suppress per-issue terminal output to prevent interleaving.
 423→  // The caller (run.ts) handles progress display via updateProgress().
 424→  const log = config.parallel ? () => {} : console.log.bind(console);
 425→
 426→  log(chalk.blue(`\n  Issue #${issueNumber}`));
 427→  if (worktreePath) {
 428→    log(chalk.gray(`    Worktree: ${worktreePath}`));
 429→  }
 430→
 431→  // Initialize state tracking for this issue
 432→  if (stateManager) {
 433→    try {
 434→      const existingState = await stateManager.getIssueState(issueNumber);
 435→      if (!existingState) {
 436→        await stateManager.initializeIssue(issueNumber, issueTitle, {
 437→          worktree: worktreePath,
 438→          branch,
 439→          qualityLoop: config.qualityLoop,
 440→          maxIterations: config.maxIterations,
 441→        });
 442→      } else {
 443→        // Update worktree info if it changed
 444→        if (worktreePath && branch) {
 445→          await stateManager.updateWorktreeInfo(
 446→            issueNumber,
 447→            worktreePath,
 448→            branch,
 449→          );
 450→        }
 451→      }
 452→    } catch (error) {
 453→      // State tracking errors shouldn't stop execution
 454→      if (config.verbose) {
 455→        log(chalk.yellow(`    ⚠️  State tracking error: ${error}`));
 456→      }
 457→    }
 458→  }
 459→
 460→  // Determine phases for this specific issue
 461→  let phases: Phase[];
 462→  let detectedQualityLoop = false;
 463→  let specAlreadyRan = false;
 464→
 465→  if (options.autoDetectPhases) {
 466→    // Check if labels indicate a simple bug/fix (skip spec entirely)
 467→    const lowerLabels = labels.map((l) => l.toLowerCase());
 468→    const isSimpleBugFix = lowerLabels.some((label) =>
 469→      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 470→    );
 471→
 472→    // Check if labels indicate documentation-only work (skip spec)
 473→    const isDocs = lowerLabels.some((label) =>
 474→      DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 475→    );
 476→
 477→    if (isSimpleBugFix) {
 478→      // Simple bug fix: skip spec, go straight to exec → qa
 479→      phases = ["exec", "qa"];
 480→      log(chalk.gray(`    Bug fix detected: ${phases.join(" → ")}`));
 481→    } else if (isDocs) {
 482→      // Documentation issue: skip spec, lighter pipeline
 483→      phases = ["exec", "qa"];
 484→      log(chalk.gray(`    Docs issue detected: ${phases.join(" → ")}`));
 485→    } else {
 486→      // Run spec first to get recommended workflow
 487→      log(chalk.gray(`    Running spec to determine workflow...`));
 488→
 489→      // Create spinner for spec phase (suppressed in parallel mode to prevent interleaving)
 490→      const specSpinner = config.parallel
 491→        ? undefined
 492→        : new PhaseSpinner({
 493→            phase: "spec",
 494→            phaseIndex: 1,
 495→            totalPhases: 3, // Estimate; will be refined after spec
 496→            shutdownManager,
 497→          });
 498→      specSpinner?.start();
 499→      emitProgressLine(issueNumber, "spec", "start");
 500→
 501→      // Track spec phase start in state
 502→      if (stateManager) {
 503→        try {
 504→          await stateManager.updatePhaseStatus(
 505→            issueNumber,
 506→            "spec",
 507→            "in_progress",
 508→          );
 509→        } catch {
 510→          // State tracking errors shouldn't stop execution
 511→        }
 512→      }
 513→
 514→      const specStartTime = new Date();
 515→      // Note: spec runs in main repo (not worktree) for planning
 516→      const specResult = await executePhaseWithRetry(
 517→        issueNumber,
 518→        "spec",
 519→        config,
 520→        sessionId,
 521→        worktreePath, // Will be ignored for spec (non-isolated phase)
 522→        shutdownManager,
 523→        specSpinner,
 524→      );
 525→      const specEndTime = new Date();
 526→
 527→      if (specResult.sessionId) {
 528→        sessionId = specResult.sessionId;
 529→        // Update session ID in state for resume capability
 530→        if (stateManager) {
 531→          try {
 532→            await stateManager.updateSessionId(
 533→              issueNumber,
 534→              specResult.sessionId,
 535→            );
 536→          } catch {
 537→            // State tracking errors shouldn't stop execution
 538→          }
 539→        }
 540→      }
 541→
 542→      phaseResults.push(specResult);
 543→      specAlreadyRan = true;
 544→
 545→      // Emit completion/failure progress event (AC-8)
 546→      const specDurationSec = Math.round(
 547→        (specEndTime.getTime() - specStartTime.getTime()) / 1000,
 548→      );
 549→      if (specResult.success) {
 550→        emitProgressLine(issueNumber, "spec", "complete", {
 551→          durationSeconds: specDurationSec,
 552→        });
 553→      } else {
 554→        emitProgressLine(issueNumber, "spec", "failed", {
 555→          error: specResult.error ?? "unknown",
 556→        });
 557→      }
 558→
 559→      // Log spec phase result
 560→      // Note: Spec runs in main repo, not worktree, so no git diff stats
 561→      if (logWriter) {
 562→        // Build errorContext from captured stderr/stdout tails (#447)
 563→        let specErrorContext: ErrorContext | undefined;
 564→        if (!specResult.success && specResult.stderrTail) {
 565→          specErrorContext = {
 566→            stderrTail: specResult.stderrTail ?? [],
 567→            stdoutTail: specResult.stdoutTail ?? [],
 568→            exitCode: specResult.exitCode,
 569→            category: classifyError(specResult.stderrTail ?? []),
 570→          };
 571→        }
 572→        const phaseLog = createPhaseLogFromTiming(
 573→          "spec",
 574→          issueNumber,
 575→          specStartTime,
 576→          specEndTime,
 577→          specResult.success
 578→            ? "success"
 579→            : specResult.error?.includes("Timeout")
 580→              ? "timeout"
 581→              : "failure",
 582→          { error: specResult.error, errorContext: specErrorContext },
 583→        );
 584→        logWriter.logPhase(phaseLog);
 585→      }
 586→
 587→      // Track spec phase completion in state
 588→      if (stateManager) {
 589→        try {
 590→          const phaseStatus = specResult.success ? "completed" : "failed";
 591→          await stateManager.updatePhaseStatus(
 592→            issueNumber,
 593→            "spec",
 594→            phaseStatus,
 595→            {
 596→              error: specResult.error,
 597→            },
 598→          );
 599→        } catch {
 600→          // State tracking errors shouldn't stop execution
 601→        }
 602→      }
 603→
 604→      if (!specResult.success) {
 605→        specSpinner?.fail(specResult.error);
 606→        const durationSeconds = (Date.now() - startTime) / 1000;
 607→        return {
 608→          issueNumber,
 609→          success: false,
 610→          phaseResults,
 611→          durationSeconds,
 612→          loopTriggered: false,
 613→        };
 614→      }
 615→
 616→      specSpinner?.succeed();
 617→
 618→      // Parse recommended workflow from spec output
 619→      const parsedWorkflow = specResult.output
 620→        ? parseRecommendedWorkflow(specResult.output)
 621→        : null;
 622→
 623→      if (parsedWorkflow) {
 624→        // Remove spec from phases since we already ran it
 625→        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
 626→        detectedQualityLoop = parsedWorkflow.qualityLoop;
 627→        log(
 628→          chalk.gray(
 629→            `    Spec recommends: ${phases.join(" → ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
 630→          ),
 631→        );
 632→      } else {
 633→        // Fall back to label-based detection
 634→        log(
 635→          chalk.yellow(
 636→            `    Could not parse spec recommendation, using label-based detection`,
 637→          ),
 638→        );
 639→        const detected = detectPhasesFromLabels(labels);
 640→        phases = detected.phases.filter((p) => p !== "spec");
 641→        detectedQualityLoop = detected.qualityLoop;
 642→        log(chalk.gray(`    Fallback: ${phases.join(" → ")}`));
 643→      }
 644→    }
 645→  } else {
 646→    // Use explicit phases with adjustments
 647→    phases = determinePhasesForIssue(config.phases, labels, options);
 648→    if (phases.length !== config.phases.length) {
 649→      log(chalk.gray(`    Phases adjusted: ${phases.join(" → ")}`));
 650→    }
 651→  }
 652→
 653→  // Resume: filter out completed phases if --resume flag is set
 654→  if (options.resume) {
 655→    const resumeResult = filterResumedPhases(issueNumber, phases, true);
 656→    if (resumeResult.skipped.length > 0) {
 657→      log(
 658→        chalk.gray(
 659→          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
 660→        ),
 661→      );
 662→      phases = resumeResult.phases;
 663→    }
 664→    // Also skip spec if it was auto-detected as completed
 665→    if (
 666→      specAlreadyRan &&
 667→      resumeResult.skipped.length === 0 &&
 668→      resumeResult.phases.length === 0
 669→    ) {
 670→      log(chalk.gray(`    Resume: all phases already completed`));
 671→    }
 672→  }
 673→
 674→  // Add testgen phase if requested (and spec was in the phases)
 675→  if (
 676→    options.testgen &&
 677→    (phases.includes("spec") || specAlreadyRan) &&
 678→    !phases.includes("testgen")
 679→  ) {
 680→    // Insert testgen at the beginning if spec already ran, otherwise after spec
 681→    if (specAlreadyRan) {
 682→      phases.unshift("testgen");
 683→    } else {
 684→      const specIndex = phases.indexOf("spec");
 685→      if (specIndex !== -1) {
 686→        phases.splice(specIndex + 1, 0, "testgen");
 687→      }
 688→    }
 689→  }
 690→
 691→  // Build per-issue config with issue type metadata for skill env propagation
 692→  const lowerLabelsForType = labels.map((l) => l.toLowerCase());
 693→  const issueIsDocs = lowerLabelsForType.some((label) =>
 694→    DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 695→  );
 696→  const issueConfig: ExecutionConfig = issueIsDocs
 697→    ? { ...config, issueType: "docs" }
 698→    : config;
 699→
 700→  let iteration = 0;
 701→  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
 702→  const maxIterations = useQualityLoop ? config.maxIterations : 1;
 703→  let completedSuccessfully = false;
 704→
 705→  while (iteration < maxIterations) {
 706→    iteration++;
 707→
 708→    if (useQualityLoop && iteration > 1) {
 709→      log(
 710→        chalk.yellow(
 711→          `    Quality loop iteration ${iteration}/${maxIterations}`,
 712→        ),
 713→      );
 714→      loopTriggered = true;
 715→    }
 716→
 717→    let phasesFailed = false;
 718→
 719→    // Calculate total phases for progress indicator
 720→    // If spec already ran in auto-detect mode, it's counted separately
 721→    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
 722→    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
 723→
 724→    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
 725→      const phase = phases[phaseIdx];
 726→      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
 727→
 728→      // Create spinner for this phase (suppressed in parallel mode)
 729→      const phaseSpinner = config.parallel
 730→        ? undefined
 731→        : new PhaseSpinner({
 732→            phase,
 733→            phaseIndex: phaseNumber,
 734→            totalPhases,
 735→            shutdownManager,
 736→            iteration: useQualityLoop ? iteration : undefined,
 737→          });
 738→      phaseSpinner?.start();
 739→      emitProgressLine(issueNumber, phase, "start");
 740→
 741→      // Track phase start in state
 742→      if (stateManager) {
 743→        try {
 744→          await stateManager.updatePhaseStatus(
 745→            issueNumber,
 746→            phase as Phase,
 747→            "in_progress",
 748→          );
 749→        } catch {
 750→          // State tracking errors shouldn't stop execution
 751→        }
 752→      }
 753→
 754→      const phaseStartTime = new Date();
 755→      const result = await executePhaseWithRetry(
 756→        issueNumber,
 757→        phase,
 758→        issueConfig,
 759→        sessionId,
 760→        worktreePath,
 761→        shutdownManager,
 762→        phaseSpinner,
 763→      );
 764→      const phaseEndTime = new Date();
 765→
 766→      // Capture session ID for subsequent phases
 767→      if (result.sessionId) {
 768→        sessionId = result.sessionId;
 769→        // Update session ID in state for resume capability
 770→        if (stateManager) {
 771→          try {
 772→            await stateManager.updateSessionId(issueNumber, result.sessionId);
 773→          } catch {
 774→            // State tracking errors shouldn't stop execution
 775→          }
 776→        }
 777→      }
 778→
 779→      phaseResults.push(result);
 780→
 781→      // Emit completion/failure progress event (AC-8)
 782→      const phaseDurationSec = Math.round(
 783→        (phaseEndTime.getTime() - phaseStartTime.getTime()) / 1000,
 784→      );
 785→      if (result.success) {
 786→        emitProgressLine(issueNumber, phase, "complete", {
 787→          durationSeconds: phaseDurationSec,
 788→        });
 789→      } else {
 790→        emitProgressLine(issueNumber, phase, "failed", {
 791→          error: result.error ?? "unknown",
 792→        });
 793→      }
 794→
 795→      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
 796→      if (logWriter) {
 797→        // Capture git diff stats for worktree phases (AC-1, AC-3)
 798→        const diffStats = worktreePath
 799→          ? getGitDiffStats(worktreePath, baseBranch)
 800→          : undefined;
 801→
 802→        // Capture commit hash after phase (AC-2)
 803→        const commitHash = worktreePath
 804→          ? getCommitHash(worktreePath)
 805→          : undefined;
 806→
 807→        // Read cache metrics for QA phase (AC-7)
 808→        const cacheMetrics =
 809→          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
 810→
 811→        // Build errorContext from captured stderr/stdout tails (#447)
 812→        let errorContext: ErrorContext | undefined;
 813→        if (!result.success && result.stderrTail) {
 814→          errorContext = {
 815→            stderrTail: result.stderrTail ?? [],
 816→            stdoutTail: result.stdoutTail ?? [],
 817→            exitCode: result.exitCode,
 818→            category: classifyError(result.stderrTail ?? []),
 819→          };
 820→        }
 821→
 822→        const phaseLog = createPhaseLogFromTiming(
 823→          phase,
 824→          issueNumber,
 825→          phaseStartTime,
 826→          phaseEndTime,
 827→          result.success
 828→            ? "success"
 829→            : result.error?.includes("Timeout")
 830→              ? "timeout"
 831→              : "failure",
 832→          {
 833→            error: result.error,
 834→            verdict: result.verdict,
 835→            // Observability fields (AC-1, AC-2, AC-3, AC-7)
 836→            filesModified: diffStats?.filesModified,
 837→            fileDiffStats: diffStats?.fileDiffStats,
 838→            commitHash,
 839→            cacheMetrics,
 840→            errorContext,
 841→          },
 842→        );
 843→        logWriter.logPhase(phaseLog);
 844→      }
 845→
 846→      // Track phase completion in state
 847→      if (stateManager) {
 848→        try {
 849→          const phaseStatus = result.success
 850→            ? "completed"
 851→            : result.error?.includes("Timeout")
 852→              ? "failed"
 853→              : "failed";
 854→          await stateManager.updatePhaseStatus(
 855→            issueNumber,
 856→            phase as Phase,
 857→            phaseStatus,
 858→            { error: result.error },
 859→          );
 860→        } catch {
 861→          // State tracking errors shouldn't stop execution
 862→        }
 863→      }
 864→
 865→      if (result.success) {
 866→        phaseSpinner?.succeed();
 867→      } else {
 868→        phaseSpinner?.fail(result.error);
 869→        phasesFailed = true;
 870→
 871→        // If quality loop enabled, run loop phase to fix issues
 872→        if (useQualityLoop && iteration < maxIterations) {
 873→          // Create spinner for loop phase (suppressed in parallel mode)
 874→          const loopSpinner = config.parallel
 875→            ? undefined
 876→            : new PhaseSpinner({
 877→                phase: "loop",
 878→                phaseIndex: phaseNumber,
 879→                totalPhases,
 880→                shutdownManager,
 881→                iteration,
 882→              });
 883→          loopSpinner?.start();
 884→          emitProgressLine(issueNumber, "loop", "start");
 885→
 886→          const loopStartTime = new Date();
 887→          const loopResult = await executePhaseWithRetry(
 888→            issueNumber,
 889→            "loop",
 890→            issueConfig,
 891→            sessionId,
 892→            worktreePath,
 893→            shutdownManager,
 894→            loopSpinner,
 895→          );
 896→          const loopEndTime = new Date();
 897→          phaseResults.push(loopResult);
 898→
 899→          // Emit loop completion/failure progress event (AC-8)
 900→          const loopDurationSec = Math.round(
 901→            (loopEndTime.getTime() - loopStartTime.getTime()) / 1000,
 902→          );
 903→          if (loopResult.success) {
 904→            emitProgressLine(issueNumber, "loop", "complete", {
 905→              durationSeconds: loopDurationSec,
 906→            });
 907→          } else {
 908→            emitProgressLine(issueNumber, "loop", "failed", {
 909→              error: loopResult.error ?? "unknown",
 910→            });
 911→          }
 912→
 913→          if (loopResult.sessionId) {
 914→            sessionId = loopResult.sessionId;
 915→          }
 916→
 917→          if (loopResult.success) {
 918→            loopSpinner?.succeed();
 919→            // Continue to next iteration
 920→            break;
 921→          } else {
 922→            loopSpinner?.fail(loopResult.error);
 923→          }
 924→        }
 925→
 926→        // Stop on first failure (if not in quality loop or loop failed)
 927→        break;
 928→      }
 929→    }
 930→
 931→    // If all phases passed, exit the loop
 932→    if (!phasesFailed) {
 933→      completedSuccessfully = true;
 934→      break;
 935→    }
 936→
 937→    // If we're not in quality loop mode, don't retry
 938→    if (!config.qualityLoop) {
 939→      break;
 940→    }
 941→  }
 942→
 943→  const durationSeconds = (Date.now() - startTime) / 1000;
 944→  // Success is determined by whether all phases completed in any iteration,
 945→  // not whether all accumulated phase results passed (which would fail after loop recovery)
 946→  const success = completedSuccessfully;
 947→
 948→  // Update final issue status in state
 949→  if (stateManager) {
 950→    try {
 951→      const finalStatus = success ? "ready_for_merge" : "in_progress";
 952→      await stateManager.updateIssueStatus(issueNumber, finalStatus);
 953→    } catch {
 954→      // State tracking errors shouldn't stop execution
 955→    }
 956→  }
 957→
 958→  // Create checkpoint commit in chain mode after QA passes
 959→  if (success && chainMode && worktreePath) {
 960→    createCheckpointCommit(worktreePath, issueNumber, config.verbose);
 961→  }
 962→
 963→  // Rebase onto the base branch before PR creation (unless --no-rebase)
 964→  // This ensures the branch is up-to-date and prevents lockfile drift
 965→  // AC-1: Non-chain mode rebases onto the base branch before PR
 966→  // AC-2: Chain mode rebases only the final branch onto the base branch before PR
 967→  //        (intermediate branches must stay based on their predecessor)
 968→  const shouldRebase =
 969→    success &&
 970→    worktreePath &&
 971→    !options.noRebase &&
 972→    (!chainMode || isLastInChain);
 973→  if (shouldRebase) {
 974→    rebaseBeforePR(
 975→      worktreePath,
 976→      issueNumber,
 977→      packageManager,
 978→      config.verbose,
 979→      baseBranch,
 980→    );
 981→  }
 982→
 983→  // Create PR after successful QA + rebase (unless --no-pr)
 984→  let prNumber: number | undefined;
 985→  let prUrl: string | undefined;
 986→  const shouldCreatePR = success && worktreePath && branch && !options.noPr;
 987→  if (shouldCreatePR) {
 988→    const prResult = createPR(
 989→      worktreePath,
 990→      issueNumber,
 991→      issueTitle,
 992→      branch,
 993→      config.verbose,
 994→      labels,
 995→    );
 996→    if (prResult.success && prResult.prNumber && prResult.prUrl) {
 997→      prNumber = prResult.prNumber;
 998→      prUrl = prResult.prUrl;
 999→
1000→      // Update workflow state with PR info
1001→      if (stateManager) {
1002→        try {
1003→          await stateManager.updatePRInfo(issueNumber, {
1004→            number: prResult.prNumber,
1005→            url: prResult.prUrl,
1006→          });
1007→        } catch {
1008→          // State tracking errors shouldn't stop execution
1009→        }
1010→      }
1011→    }
1012→  }
1013→
1014→  return {
1015→    issueNumber,
1016→    success,
1017→    phaseResults,
1018→    durationSeconds,
1019→    loopTriggered,
1020→    prNumber,
1021→    prUrl,
1022→  };
1023→}
