  2→ * Reconciliation engine for sequant status
  3→ *
  4→ * Reconciles local state.json with GitHub API and filesystem
  5→ * to provide accurate, up-to-date status information.
  6→ *
  7→ * @module reconcile
  8→ */
  9→
 10→import * as fs from "fs";
 11→import { StateManager } from "./state-manager.js";
 12→import {
 13→  GitHubProvider,
 14→  type BatchIssueInfo,
 15→  type BatchPRInfo,
 16→} from "./platforms/github.js";
 17→import type { IssueState, IssueStatus } from "./state-schema.js";
 18→
 19→/**
 20→ * Classification of detected drift between local state and reality.
 21→ */
 22→export type DriftType = "unambiguous" | "ambiguous" | "none";
 23→
 24→/**
 25→ * A single drift action detected during reconciliation.
 26→ */
 27→export interface DriftAction {
 28→  issueNumber: number;
 29→  type: DriftType;
 30→  action: string;
 31→  description: string;
 32→}
 33→
 34→/**
 35→ * Result of a reconciliation operation.
 36→ */
 37→export interface ReconcileResult {
 38→  success: boolean;
 39→  /** Actions taken (unambiguous drift auto-healed). */
 40→  healed: DriftAction[];
 41→  /** Ambiguous drift flagged to user. */
 42→  warnings: DriftAction[];
 43→  /** ISO timestamp of when reconciliation completed. */
 44→  lastSynced: string;
 45→  /** Whether GitHub was reachable. */
 46→  githubReachable: boolean;
 47→  /** Error message if reconciliation failed entirely. */
 48→  error?: string;
 49→}
 50→
 51→/**
 52→ * Options for reconciliation.
 53→ */
 54→export interface ReconcileOptions {
 55→  /** Skip GitHub API queries (offline mode). */
 56→  offline?: boolean;
 57→  /** State manager to use. */
 58→  stateManager?: StateManager;
 59→}
 60→
 61→/**
 62→ * Classify drift for a single issue based on GitHub and filesystem state.
 63→ */
 64→export function classifyDrift(
 65→  issue: IssueState,
 66→  githubIssue?: BatchIssueInfo,
 67→  githubPR?: BatchPRInfo,
 68→  worktreeExists?: boolean,
 69→): DriftAction | null {
 70→  const num = issue.number;
 71→
 72→  // Check PR merge → unambiguous
 73→  if (githubPR?.state === "MERGED" && issue.status !== "merged") {
 74→    return {
 75→      issueNumber: num,
 76→      type: "unambiguous",
 77→      action: "update_to_merged",
 78→      description: `PR #${githubPR.number} merged on GitHub`,
 79→    };
 80→  }
 81→
 82→  // Check issue closed + no merged PR → unambiguous abandoned
 83→  if (
 84→    githubIssue?.state === "CLOSED" &&
 85→    issue.status !== "merged" &&
 86→    issue.status !== "abandoned" &&
 87→    githubPR?.state !== "MERGED"
 88→  ) {
 89→    return {
 90→      issueNumber: num,
 91→      type: "unambiguous",
 92→      action: "update_to_abandoned",
 93→      description: `Issue #${num} closed on GitHub without merged PR`,
 94→    };
 95→  }
 96→
 97→  // Check worktree missing
 98→  if (issue.worktree && worktreeExists === false) {
 99→    if (!issue.pr?.number) {
100→      if (githubIssue?.state === "OPEN") {
101→        // Confirmed open on GitHub, no PR → ambiguous
102→        return {
103→          issueNumber: num,
104→          type: "ambiguous",
105→          action: "flag_missing_worktree",
106→          description: `Worktree deleted but issue #${num} still open on GitHub with no PR`,
107→        };
108→      }
109→      if (!githubIssue) {
110→        // GitHub data unavailable → ambiguous (can't determine if safe to clear)
111→        return {
112→          issueNumber: num,
113→          type: "ambiguous",
114→          action: "flag_missing_worktree",
115→          description: `Worktree deleted for issue #${num} but GitHub state unknown (API unreachable)`,
116→        };
117→      }
118→    }
119→    // Otherwise just clear worktree (unambiguous)
120→    return {
121→      issueNumber: num,
122→      type: "unambiguous",
123→      action: "clear_worktree",
124→      description: `Worktree path no longer exists for issue #${num}`,
125→    };
126→  }
127→
128→  // Check local abandoned but GitHub open → ambiguous
129→  if (issue.status === "abandoned" && githubIssue?.state === "OPEN") {
130→    return {
131→      issueNumber: num,
132→      type: "ambiguous",
133→      action: "flag_status_mismatch",
134→      description: `Issue #${num} marked abandoned locally but still open on GitHub`,
135→    };
136→  }
137→
138→  return null;
139→}
