178→/**
179→ * Format a relative time string from an ISO timestamp.
180→ */
181→export function formatRelativeTime(isoTimestamp: string | undefined): string {
182→  if (!isoTimestamp) return "unknown";
183→
184→  const date = new Date(isoTimestamp);
185→  if (isNaN(date.getTime())) return "unknown";
186→
187→  const now = new Date();
188→  const diffMs = now.getTime() - date.getTime();
189→
190→  // Handle future timestamps (clock skew)
191→  if (diffMs < 0) return "just now";
192→
193→  const diffSec = Math.floor(diffMs / 1000);
194→  const diffMin = Math.floor(diffSec / 60);
195→  const diffHour = Math.floor(diffMin / 60);
196→  const diffDay = Math.floor(diffHour / 24);
197→
198→  if (diffSec < 60) return "just now";
199→  if (diffMin < 60) return `${diffMin} minute${diffMin > 1 ? "s" : ""} ago`;
200→  if (diffHour < 24) return `${diffHour} hour${diffHour > 1 ? "s" : ""} ago`;
201→  if (diffDay < 7) return `${diffDay} day${diffDay > 1 ? "s" : ""} ago`;
202→  return date.toLocaleDateString();
203→}
