112→/**
113→ * Main run command
114→ */
115→export async function runCommand(
116→  issues: string[],
117→  options: RunOptions,
118→): Promise<void> {
119→  console.log(ui.headerBox("SEQUANT WORKFLOW"));
120→
121→  // Version freshness check (cached, non-blocking, respects --quiet)
122→  if (!options.quiet) {
123→    try {
124→      const versionResult = await checkVersionCached();
125→      if (versionResult.isOutdated && versionResult.latestVersion) {
126→        console.log(
127→          chalk.yellow(
128→            `  ⚠️  ${getVersionWarning(versionResult.currentVersion, versionResult.latestVersion, versionResult.isLocalInstall)}`,
129→          ),
130→        );
131→        console.log("");
132→      }
133→    } catch {
134→      // Silent failure - version check is non-critical
135→    }
136→  }
137→
138→  // Check if initialized
139→  const manifest = await getManifest();
140→  if (!manifest) {
141→    console.log(
142→      chalk.red("❌ Sequant is not initialized. Run `sequant init` first."),
143→    );
144→    return;
145→  }
146→
147→  // Load settings and merge with environment config and CLI options
148→  const settings = await getSettings();
149→  const envConfig = getEnvConfig();
150→
151→  // Settings provide defaults, env overrides settings, CLI overrides all
152→  // Note: phases are auto-detected per-issue unless --phases is explicitly set
153→  // Commander.js converts --no-X to { X: false }, not { noX: true }.
154→  // Normalize these so RunOptions fields (noLog, noMcp, etc.) work correctly.
155→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
156→  const cliOpts = options as any;
157→  const normalizedOptions: RunOptions = {
158→    ...options,
159→    ...(cliOpts.log === false && { noLog: true }),
160→    ...(cliOpts.smartTests === false && { noSmartTests: true }),
161→    ...(cliOpts.mcp === false && { noMcp: true }),
162→    ...(cliOpts.retry === false && { noRetry: true }),
163→    ...(cliOpts.rebase === false && { noRebase: true }),
164→    ...(cliOpts.pr === false && { noPr: true }),
165→  };
166→
167→  const mergedOptions: RunOptions = {
168→    // Settings defaults (phases removed - now auto-detected)
169→    sequential: normalizedOptions.sequential ?? settings.run.sequential,
170→    concurrency: normalizedOptions.concurrency ?? settings.run.concurrency,
171→    timeout: normalizedOptions.timeout ?? settings.run.timeout,
172→    logPath: normalizedOptions.logPath ?? settings.run.logPath,
173→    qualityLoop: normalizedOptions.qualityLoop ?? settings.run.qualityLoop,
174→    maxIterations:
175→      normalizedOptions.maxIterations ?? settings.run.maxIterations,
176→    noSmartTests: normalizedOptions.noSmartTests ?? !settings.run.smartTests,
177→    // Env overrides
178→    ...envConfig,
179→    // CLI explicit options override all
180→    ...normalizedOptions,
181→  };
182→
183→  // Determine if we should auto-detect phases from labels
