190→    settings.run.defaultBase ??
191→    detectDefaultBranch(mergedOptions.verbose ?? false);
192→
193→  // Parse issue numbers (or use batch mode)
194→  let issueNumbers: number[];
195→  let batches: number[][] | null = null;
196→
197→  if (mergedOptions.batch && mergedOptions.batch.length > 0) {
198→    batches = parseBatches(mergedOptions.batch);
199→    issueNumbers = batches.flat();
200→    console.log(
201→      chalk.gray(
202→        `  Batch mode: ${batches.map((b) => `[${b.join(", ")}]`).join(" → ")}`,
203→      ),
204→    );
205→  } else {
206→    issueNumbers = issues.map((i) => parseInt(i, 10)).filter((n) => !isNaN(n));
207→  }
208→
209→  if (issueNumbers.length === 0) {
210→    console.log(chalk.red("❌ No valid issue numbers provided."));
211→    console.log(chalk.gray("\nUsage: npx sequant run <issues...> [options]"));
212→    console.log(chalk.gray("Example: npx sequant run 1 2 3 --sequential"));
213→    console.log(
214→      chalk.gray('Batch example: npx sequant run --batch "1 2" --batch "3"'),
215→    );
216→    console.log(chalk.gray("Chain example: npx sequant run 1 2 3 --chain"));
217→    return;
218→  }
219→
220→  // Validate chain mode requirements
221→  if (mergedOptions.chain) {
222→    // Chain mode is inherently sequential — imply --sequential automatically
223→    if (!mergedOptions.sequential) {
224→      mergedOptions.sequential = true;
225→    }
226→
227→    if (batches) {
228→      console.log(chalk.red("❌ --chain cannot be used with --batch"));
229→      console.log(
230→        chalk.gray(
231→          "   Chain mode creates a linear dependency chain between issues.",
232→        ),
233→      );
234→      return;
235→    }
236→
237→    // Warn about long chains
238→    if (issueNumbers.length > 5) {
239→      console.log(
240→        chalk.yellow(
241→          `  ⚠️  Warning: Chain has ${issueNumbers.length} issues (recommended max: 5)`,
242→        ),
243→      );
244→      console.log(
245→        chalk.yellow(
246→          "     Long chains increase merge complexity and review difficulty.",
247→        ),
248→      );
249→      console.log(
250→        chalk.yellow(
251→          "     Consider breaking into smaller chains or using batch mode.",
252→        ),
253→      );
254→      console.log("");
255→    }
256→  }
257→
258→  // Validate concurrency value
259→  if (
260→    mergedOptions.concurrency !== undefined &&
261→    (mergedOptions.concurrency < 1 ||
262→      !Number.isInteger(mergedOptions.concurrency))
263→  ) {
264→    console.log(
265→      chalk.red(
266→        `❌ Invalid --concurrency value: ${mergedOptions.concurrency}. Must be a positive integer.`,
267→      ),
268→    );
269→    return;
270→  }
271→
272→  // Validate QA gate requirements
273→  if (mergedOptions.qaGate && !mergedOptions.chain) {
274→    console.log(chalk.red("❌ --qa-gate requires --chain flag"));
275→    console.log(
276→      chalk.gray(
277→        "   QA gate ensures each issue passes QA before the next issue starts.",
278→      ),
279→    );
280→    console.log(
281→      chalk.gray(
282→        "   Usage: npx sequant run 1 2 3 --sequential --chain --qa-gate",
283→      ),
284→    );
285→    return;
286→  }
287→
288→  // Sort issues by dependencies (if more than one issue)
289→  if (issueNumbers.length > 1 && !batches) {
290→    const originalOrder = [...issueNumbers];
291→    issueNumbers = sortByDependencies(issueNumbers);
292→    const orderChanged = !originalOrder.every((n, i) => n === issueNumbers[i]);
293→    if (orderChanged) {
294→      console.log(
295→        chalk.gray(
296→          `  Dependency order: ${issueNumbers.map((n) => `#${n}`).join(" → ")}`,
297→        ),
298→      );
299→    }
300→  }
301→
302→  // Build config
303→  // Note: config.phases is only used when --phases is explicitly set or autoDetect fails
304→  const explicitPhases = mergedOptions.phases
305→    ? (mergedOptions.phases.split(",").map((p) => p.trim()) as Phase[])
306→    : null;
307→
308→  // Determine MCP enablement: CLI flag (--no-mcp) → settings.run.mcp → default (true)
309→  const mcpEnabled = mergedOptions.noMcp
310→    ? false
311→    : (settings.run.mcp ?? DEFAULT_CONFIG.mcp);
312→
313→  // Resolve retry setting: CLI flag → settings.run.retry → default (true)
314→  const retryEnabled = mergedOptions.noRetry
315→    ? false
316→    : (settings.run.retry ?? true);
317→
318→  const isSequential = mergedOptions.sequential ?? false;
319→  const isParallel = !isSequential && issueNumbers.length > 1;
320→
321→  const config: ExecutionConfig = {
322→    ...DEFAULT_CONFIG,
323→    phases: explicitPhases ?? DEFAULT_PHASES,
324→    sequential: isSequential,
325→    concurrency: mergedOptions.concurrency ?? DEFAULT_CONFIG.concurrency,
326→    parallel: isParallel,
327→    dryRun: mergedOptions.dryRun ?? false,
328→    verbose: mergedOptions.verbose ?? false,
329→    phaseTimeout: mergedOptions.timeout ?? DEFAULT_CONFIG.phaseTimeout,
330→    qualityLoop: mergedOptions.qualityLoop ?? false,
331→    maxIterations: mergedOptions.maxIterations ?? DEFAULT_CONFIG.maxIterations,
332→    noSmartTests: mergedOptions.noSmartTests ?? false,
333→    mcp: mcpEnabled,
334→    retry: retryEnabled,
335→    agent: mergedOptions.agent ?? settings.run.agent,
336→    aiderSettings: settings.run.aider,
337→  };
338→
339→  // Propagate verbose mode to UI config so spinners use text-only mode.
340→  // This prevents animated spinner control characters from colliding with
341→  // verbose console.log() calls from StateManager/MetricsWriter (#282).
342→  if (config.verbose) {
343→    ui.configure({ verbose: true });
344→  }
345→
346→  // Initialize log writer if JSON logging enabled
347→  // Default: enabled via settings (logJson: true), can be disabled with --no-log
348→  let logWriter: LogWriter | null = null;
349→  const shouldLog =
350→    !mergedOptions.noLog &&
351→    !config.dryRun &&
352→    (mergedOptions.logJson ?? settings.run.logJson);
353→
354→  if (shouldLog) {
355→    const runConfig: RunConfig = {
356→      phases: config.phases,
357→      sequential: config.sequential,
358→      qualityLoop: config.qualityLoop,
359→      maxIterations: config.maxIterations,
360→      chain: mergedOptions.chain,
361→      qaGate: mergedOptions.qaGate,
362→    };
363→
364→    try {
365→      logWriter = new LogWriter({
366→        logPath: mergedOptions.logPath ?? settings.run.logPath,
367→        verbose: config.verbose,
368→        startCommit: getCommitHash(process.cwd()),
369→      });
370→      await logWriter.initialize(runConfig);
371→    } catch (err) {
372→      // Log initialization failure is non-fatal - warn and continue without logging
373→      // Common causes: permissions issues, disk full, invalid path
374→      const errorMessage = err instanceof Error ? err.message : String(err);
375→      console.log(
376→        chalk.yellow(
377→          `  ⚠️ Log initialization failed, continuing without logging: ${errorMessage}`,
378→        ),
379→      );
380→      logWriter = null;
381→    }
382→  }
383→
384→  // Initialize state manager for persistent workflow state tracking
385→  // State tracking is always enabled (unless dry run)
386→  let stateManager: StateManager | null = null;
387→  if (!config.dryRun) {
388→    stateManager = new StateManager({ verbose: config.verbose });
389→  }
390→
391→  // Initialize shutdown manager for graceful interruption handling
392→  const shutdown = new ShutdownManager();
393→
394→  // Register log writer finalization as cleanup task
395→  if (logWriter) {
396→    const writer = logWriter; // Capture for closure
397→    shutdown.registerCleanup("Finalize run logs", async () => {
398→      await writer.finalize();
399→    });
400→  }
401→
402→  // Display configuration
403→  console.log(chalk.gray(`  Stack: ${manifest.stack}`));
404→  if (autoDetectPhases) {
405→    console.log(chalk.gray(`  Phases: auto-detect from labels`));
406→  } else {
407→    console.log(chalk.gray(`  Phases: ${config.phases.join(" → ")}`));
408→  }
409→  console.log(
410→    chalk.gray(
411→      `  Mode: ${config.sequential ? "sequential (stop-on-failure)" : `parallel (concurrency: ${config.concurrency})`}`,
412→    ),
413→  );
414→  if (config.qualityLoop) {
415→    console.log(
416→      chalk.gray(
417→        `  Quality loop: enabled (max ${config.maxIterations} iterations)`,
418→      ),
419→    );
420→  }
421→  if (mergedOptions.testgen) {
422→    console.log(chalk.gray(`  Testgen: enabled`));
423→  }
424→  if (config.noSmartTests) {
425→    console.log(chalk.gray(`  Smart tests: disabled`));
426→  }
427→  if (config.dryRun) {
428→    console.log(chalk.yellow(`  ⚠️  DRY RUN - no actual execution`));
429→  }
430→  if (logWriter) {
431→    console.log(
432→      chalk.gray(
433→        `  Logging: JSON (run ${logWriter.getRunId()?.slice(0, 8)}...)`,
434→      ),
435→    );
436→  }
437→  if (stateManager) {
438→    console.log(chalk.gray(`  State tracking: enabled`));
439→  }
440→  if (mergedOptions.force) {
441→    console.log(chalk.yellow(`  Force mode: enabled (bypass state guard)`));
442→  }
443→  console.log(
444→    chalk.gray(`  Issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`),
445→  );
446→
447→  // ============================================================================
448→  // Pre-flight State Guard (#305)
449→  // ============================================================================
450→
451→  // AC-5: Auto-cleanup at run start - reconcile stale ready_for_merge states
452→  if (stateManager && !config.dryRun) {
453→    try {
454→      const reconcileResult = await reconcileStateAtStartup({
455→        verbose: config.verbose,
456→      });
457→
458→      if (reconcileResult.success && reconcileResult.advanced.length > 0) {
459→        console.log(
460→          chalk.gray(
461→            `  State reconciled: ${reconcileResult.advanced.map((n) => `#${n}`).join(", ")} → merged`,
462→          ),
463→        );
464→      }
465→    } catch (error) {
466→      // AC-8: Graceful degradation - don't block execution on reconciliation failure
467→      logNonFatalWarning(
468→        `  ⚠️  State reconciliation failed, continuing...`,
469→        error,
470→        config.verbose,
471→      );
472→    }
473→  }
474→
475→  // AC-1 & AC-2: Pre-flight state guard - skip completed issues unless --force
476→  if (stateManager && !config.dryRun && !mergedOptions.force) {
477→    const skippedIssues: number[] = [];
478→    const activeIssues: number[] = [];
479→
480→    for (const issueNumber of issueNumbers) {
481→      try {
482→        const issueState = await stateManager.getIssueState(issueNumber);
483→        if (
484→          issueState &&
485→          (issueState.status === "ready_for_merge" ||
486→            issueState.status === "merged")
487→        ) {
488→          skippedIssues.push(issueNumber);
489→          console.log(
490→            chalk.yellow(
491→              `  ⚠️  #${issueNumber}: already ${issueState.status} — skipping (use --force to re-run)`,
492→            ),
493→          );
494→        } else {
495→          activeIssues.push(issueNumber);
496→        }
497→      } catch (error) {
498→        // AC-8: Graceful degradation - if state check fails, include the issue
499→        logNonFatalWarning(
500→          `  ⚠️  State lookup failed for #${issueNumber}, including anyway...`,

 500→          `  ⚠️  State lookup failed for #${issueNumber}, including anyway...`,
 501→          error,
 502→          config.verbose,
 503→        );
 504→        activeIssues.push(issueNumber);
 505→      }
 506→    }
 507→
 508→    // Update issueNumbers to only include active issues
 509→    if (skippedIssues.length > 0) {
 510→      issueNumbers = activeIssues;
 511→
 512→      if (issueNumbers.length === 0) {
 513→        console.log(
 514→          chalk.yellow(
 515→            `\n  All issues already completed. Use --force to re-run.`,
 516→          ),
 517→        );
 518→        return;
 519→      }
 520→
 521→      console.log(
 522→        chalk.gray(
 523→          `  Active issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`,
 524→        ),
 525→      );
 526→    }
 527→  }
 528→
 529→  // Worktree isolation is enabled by default for multi-issue runs
 530→  const useWorktreeIsolation =
 531→    mergedOptions.worktreeIsolation !== false && issueNumbers.length > 0;
 532→
 533→  if (useWorktreeIsolation) {
 534→    console.log(chalk.gray(`  Worktree isolation: enabled`));
 535→  }
 536→  if (resolvedBaseBranch) {
 537→    console.log(chalk.gray(`  Base branch: ${resolvedBaseBranch}`));
 538→  }
 539→  if (mergedOptions.chain) {
 540→    console.log(
 541→      chalk.gray(`  Chain mode: enabled (each issue branches from previous)`),
 542→    );
 543→  }
 544→  if (mergedOptions.qaGate) {
 545→    console.log(chalk.gray(`  QA gate: enabled (chain waits for QA pass)`));
 546→  }
 547→
 548→  // Fetch issue info for all issues first
 549→  const issueInfoMap = new Map<number, { title: string; labels: string[] }>();
 550→  for (const issueNumber of issueNumbers) {
 551→    issueInfoMap.set(issueNumber, await getIssueInfo(issueNumber));
 552→  }
 553→
 554→  // Create worktrees for all issues before execution (if isolation enabled)
 555→  let worktreeMap: Map<number, WorktreeInfo> = new Map();
 556→  if (useWorktreeIsolation && !config.dryRun) {
 557→    const issueData = issueNumbers.map((num) => ({
 558→      number: num,
 559→      title: issueInfoMap.get(num)?.title || `Issue #${num}`,
 560→    }));
 561→
 562→    // Use chain mode or standard worktree creation
 563→    if (mergedOptions.chain) {
 564→      worktreeMap = await ensureWorktreesChain(
 565→        issueData,
 566→        config.verbose,
 567→        manifest.packageManager,
 568→        resolvedBaseBranch,
 569→      );
 570→    } else {
 571→      worktreeMap = await ensureWorktrees(
 572→        issueData,
 573→        config.verbose,
 574→        manifest.packageManager,
 575→        resolvedBaseBranch,
 576→      );
 577→    }
 578→
 579→    // Register cleanup tasks for newly created worktrees (not pre-existing ones)
 580→    for (const [issueNum, worktree] of worktreeMap.entries()) {
 581→      if (!worktree.existed) {
 582→        shutdown.registerCleanup(
 583→          `Cleanup worktree for #${issueNum}`,
 584→          async () => {
 585→            // Remove worktree (leaves branch intact for recovery)
 586→            const result = spawnSync(
 587→              "git",
 588→              ["worktree", "remove", "--force", worktree.path],
 589→              {
 590→                stdio: "pipe",
 591→              },
 592→            );
 593→            if (result.status !== 0 && config.verbose) {
 594→              console.log(
 595→                chalk.yellow(
 596→                  `    Warning: Could not remove worktree ${worktree.path}`,
 597→                ),
 598→              );
 599→            }
 600→          },
 601→        );
 602→      }
 603→    }
 604→  }
 605→
 606→  // Execute with graceful shutdown handling
 607→  const results: IssueResult[] = [];
 608→  let exitCode = 0;
 609→
 610→  try {
 611→    if (batches) {
 612→      // Batch execution: run batches sequentially, issues within batch based on mode
 613→      for (let batchIdx = 0; batchIdx < batches.length; batchIdx++) {
 614→        const batch = batches[batchIdx];
 615→        console.log(
 616→          chalk.blue(
 617→            `\n  Batch ${batchIdx + 1}/${batches.length}: Issues ${batch.map((n) => `#${n}`).join(", ")}`,
 618→          ),
 619→        );
 620→
 621→        const batchResults = await executeBatch(
 622→          batch,
 623→          config,
 624→          logWriter,
 625→          stateManager,
 626→          mergedOptions,
 627→          issueInfoMap,
 628→          worktreeMap,
 629→          shutdown,
 630→          manifest.packageManager,
 631→          resolvedBaseBranch,
 632→        );
 633→        results.push(...batchResults);
 634→
 635→        // Check if batch failed and we should stop
 636→        const batchFailed = batchResults.some((r) => !r.success);
 637→        if (batchFailed && config.sequential) {
 638→          console.log(
 639→            chalk.yellow(
 640→              `\n  ⚠️  Batch ${batchIdx + 1} failed, stopping batch execution`,
 641→            ),
 642→          );
 643→          break;
 644→        }
 645→      }
 646→    } else if (config.sequential) {
 647→      // Sequential execution
 648→      for (let i = 0; i < issueNumbers.length; i++) {
 649→        const issueNumber = issueNumbers[i];
 650→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
 651→          title: `Issue #${issueNumber}`,
 652→          labels: [],
 653→        };
 654→        const worktreeInfo = worktreeMap.get(issueNumber);
 655→
 656→        // Start issue logging
 657→        if (logWriter) {
 658→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
 659→        }
 660→
 661→        const result = await runIssueWithLogging(
 662→          issueNumber,
 663→          config,
 664→          logWriter,
 665→          stateManager,
 666→          issueInfo.title,
 667→          issueInfo.labels,
 668→          mergedOptions,
 669→          worktreeInfo?.path,
 670→          worktreeInfo?.branch,
 671→          shutdown,
 672→          mergedOptions.chain, // Enable checkpoint commits in chain mode
 673→          manifest.packageManager,
 674→          // In chain mode, only the last issue should trigger pre-PR rebase
 675→          mergedOptions.chain ? i === issueNumbers.length - 1 : undefined,
 676→          resolvedBaseBranch,
 677→        );
 678→        results.push(result);
 679→
 680→        // Record PR info in log before completing issue
 681→        if (logWriter && result.prNumber && result.prUrl) {
 682→          logWriter.setPRInfo(result.prNumber, result.prUrl);
 683→        }
 684→
 685→        // Complete issue logging
 686→        if (logWriter) {
 687→          logWriter.completeIssue();
 688→        }
 689→
 690→        // Check if shutdown was triggered
 691→        if (shutdown.shuttingDown) {
 692→          break;
 693→        }
 694→
 695→        if (!result.success) {
 696→          // Check if QA gate is enabled and QA specifically failed
 697→          if (mergedOptions.qaGate) {
 698→            const qaResult = result.phaseResults.find((p) => p.phase === "qa");
 699→            const qaFailed = qaResult && !qaResult.success;
 700→
 701→            if (qaFailed) {
 702→              // QA gate: pause chain with clear messaging
 703→              console.log(chalk.yellow("\n  ⏸️  QA Gate"));
 704→              console.log(
 705→                chalk.yellow(
 706→                  `     Issue #${issueNumber} QA did not pass. Chain paused.`,
 707→                ),
 708→              );
 709→              console.log(
 710→                chalk.gray(
 711→                  "     Fix QA issues and re-run, or run /loop to auto-fix.",
 712→                ),
 713→              );
 714→
 715→              // Update state to waiting_for_qa_gate
 716→              if (stateManager) {
 717→                try {
 718→                  await stateManager.updateIssueStatus(
 719→                    issueNumber,
 720→                    "waiting_for_qa_gate",
 721→                  );
 722→                } catch {
 723→                  // State tracking errors shouldn't stop execution
 724→                }
 725→              }
 726→              break;
 727→            }
 728→          }
 729→
 730→          const chainInfo = mergedOptions.chain ? " (chain stopped)" : "";
 731→          console.log(
 732→            chalk.yellow(
 733→              `\n  ⚠️  Issue #${issueNumber} failed, stopping sequential execution${chainInfo}`,
 734→            ),
 735→          );
 736→          break;
 737→        }
 738→      }
 739→    } else {
 740→      // Default mode: run issues concurrently with configurable concurrency limit
 741→      const limit = pLimit(config.concurrency);
 742→
 743→      // Track progress for concurrent issues
 744→      const issueStatus = new Map<
 745→        number,
 746→        {
 747→          state: "running" | "done" | "failed";
 748→          durationSeconds?: number;
 749→          error?: string;
 750→        }
 751→      >();
 752→      for (const num of issueNumbers) {
 753→        issueStatus.set(num, { state: "running" });
 754→      }
 755→
 756→      const renderProgressLine = () => {
 757→        const parts = issueNumbers.map((num) => {
 758→          const info = issueStatus.get(num)!;
 759→          if (info.state === "done") return colors.success(`#${num} ✓`);
 760→          if (info.state === "failed") return colors.error(`#${num} ✗`);
 761→          return colors.warning(`#${num} ⏳`);
 762→        });
 763→        return `  Progress: ${parts.join("  ")}`;
 764→      };
 765→
 766→      const updateProgress = (completedIssue?: number) => {
 767→        if (mergedOptions.quiet) return;
 768→
 769→        if (process.stdout.isTTY) {
 770→          // TTY: overwrite the progress line in place
 771→          process.stdout.write(`\r${renderProgressLine()}`);
 772→        }
 773→
 774→        // Print a per-issue completion summary (works on both TTY and non-TTY)
 775→        if (completedIssue != null) {
 776→          const info = issueStatus.get(completedIssue)!;
 777→          const duration =
 778→            info.durationSeconds != null
 779→              ? ` (${formatElapsedTime(info.durationSeconds)})`
 780→              : "";
 781→          if (info.state === "done") {
 782→            const line = `  ${colors.success("✓")} Issue #${completedIssue} completed${duration}`;
 783→            if (process.stdout.isTTY) {
 784→              // Move to a new line before printing the summary, then re-render progress
 785→              process.stdout.write(`\n${line}\n${renderProgressLine()}`);
 786→            } else {
 787→              console.log(line);
 788→            }
 789→          } else {
 790→            const errorSuffix = info.error ? `: ${info.error}` : "";
 791→            const line = `  ${colors.error("✗")} Issue #${completedIssue} failed${duration}${errorSuffix}`;
 792→            if (process.stdout.isTTY) {
 793→              process.stdout.write(`\n${line}\n${renderProgressLine()}`);
 794→            } else {
 795→              console.log(line);
 796→            }
 797→          }
 798→        }
 799→      };
 800→
 801→      updateProgress();
 802→
 803→      const settledResults = await Promise.allSettled(
 804→        issueNumbers.map((issueNumber) =>
 805→          limit(async () => {
 806→            // Check if shutdown was triggered before starting
 807→            if (shutdown.shuttingDown) {
 808→              return {
 809→                issueNumber,
 810→                success: false,
 811→                phaseResults: [],
 812→                durationSeconds: 0,
 813→                loopTriggered: false,
 814→              } as IssueResult;
 815→            }
 816→
 817→            const issueInfo = issueInfoMap.get(issueNumber) ?? {
 818→              title: `Issue #${issueNumber}`,
 819→              labels: [],
 820→            };
 821→            const worktreeInfo = worktreeMap.get(issueNumber);
 822→
 823→            // Start issue logging
 824→            if (logWriter) {
 825→              logWriter.startIssue(
 826→                issueNumber,
 827→                issueInfo.title,
 828→                issueInfo.labels,
 829→              );
 830→            }
 831→
 832→            const result = await runIssueWithLogging(
 833→              issueNumber,
 834→              config,
 835→              logWriter,
 836→              stateManager,
 837→              issueInfo.title,
 838→              issueInfo.labels,
 839→              mergedOptions,
 840→              worktreeInfo?.path,
