 42→/** Create a mock ChildProcess that emits events asynchronously */
 43→function createMockProcess(opts: {
 44→  exitCode?: number | null;
 45→  stdout?: string;
 46→  stderr?: string;
 47→  stderrChunks?: string[];
 48→  stdoutChunks?: string[];
 49→  error?: Error;
 50→  delay?: number;
 51→}) {
 52→  const proc = new EventEmitter() as ReturnType<typeof spawn>;
 53→  const stdoutEmitter = new EventEmitter();
 54→  const stderrEmitter = new EventEmitter();
 55→  (proc as unknown as Record<string, unknown>).stdout = stdoutEmitter;
 56→  (proc as unknown as Record<string, unknown>).stderr = stderrEmitter;
 57→  (proc as unknown as Record<string, unknown>).pid = 12345;
 58→  (proc as unknown as Record<string, unknown>).killed = false;
 59→  (proc as unknown as Record<string, unknown>).kill = vi.fn(() => {
 60→    (proc as unknown as Record<string, unknown>).killed = true;
 61→  });
 62→
 63→  const emit = () => {
 64→    if (opts.stdoutChunks) {
 65→      for (const chunk of opts.stdoutChunks) {
 66→        stdoutEmitter.emit("data", Buffer.from(chunk));
 67→      }
 68→    } else if (opts.stdout) {
 69→      stdoutEmitter.emit("data", Buffer.from(opts.stdout));
 70→    }
 71→    if (opts.stderrChunks) {
 72→      for (const chunk of opts.stderrChunks) {
 73→        stderrEmitter.emit("data", Buffer.from(chunk));
 74→      }
 75→    } else if (opts.stderr) {
 76→      stderrEmitter.emit("data", Buffer.from(opts.stderr));
 77→    }
 78→    if (opts.error) {
 79→      proc.emit("error", opts.error);
 80→    } else {
 81→      proc.emit("close", opts.exitCode ?? 0);
 82→    }
 83→  };
 84→
 85→  if (opts.delay) {
 86→    setTimeout(emit, opts.delay);
 87→  } else {
 88→    queueMicrotask(emit);
 89→  }
 90→
 91→  return proc;
 92→}
